import java.util.HashMap;
import java.util.Map;
import java.util.Set;
import java.util.logging.Logger;

public final class GeneratorManager {

    public static final GeneratorManager INSTANCE = new GeneratorManager();
    private static final Logger LOG = Logger.getLogger(GeneratorManager.class.getName());

    private Language currLanguage;
    private final Map<Language, CodeGenerator> generators = new HashMap<>();

    private GeneratorManager() {}

    // Placeholder for the code path retrieval
    public String getCodePath() {
        return "path/to/code";
    }

    // Get a generator for a specific language
    public CodeGenerator getGenerator(Language language) {
        return generators.get(language);
    }

    // Overloaded: get the current generator
    public CodeGenerator getGenerator() {
        return getCurrGenerator();
    }

    // Get the currently selected language
    public Language getCurrLanguage() {
        return currLanguage;
    }

    // Remove a generator for a specific language
    public CodeGenerator removeGenerator(Language language) {
        return generators.remove(language);
    }

    // Get the set of languages that have generators registered
    public Set<Language> getLanguages() {
        return generators.keySet();
    }

    // Access the singleton instance
    public static GeneratorManager getInstance() {
        return INSTANCE;
    }

    // Find the language that corresponds to a given generator
    public Language findLanguage(CodeGenerator generator) {
        if (generator == null) return null;
        for (Map.Entry<Language, CodeGenerator> entry : generators.entrySet()) {
            if (generator.equals(entry.getValue())) {
                return entry.getKey();
            }
        }
        return null;
    }

    // Get the current generator
    public CodeGenerator getCurrGenerator() {
        return getGenerator(currLanguage);
    }

    // Access to the internal map of generators
    public Map<Language, CodeGenerator> getGenerators() {
        return generators;
    }

    // Register a new generator; if one exists for the same language, it is replaced
    public void registerGenerator(Language language, CodeGenerator generator) {
        if (language == null || generator == null) {
            throw new IllegalArgumentException("language and generator must be non-null");
        }
        generators.put(language, generator);
        // Do not automatically change currLanguage unless desired by design
        // If you want to set currLanguage on registration, uncomment the next line:
        // currLanguage = language;
    }
}
